# policies/genai-env.rego
package genai.env

import future.keywords.in

# Deny if GPU class is not in team's approved list
deny[msg] {
    resource := input.resource_changes[_]
    resource.type == "google_container_node_pool"
    accel := resource.change.after.node_config[_].guest_accelerator[_]
    not accel.type in data.team_gpu_allowlist[input.variables.owner.value]
    msg := sprintf(
        "GPU type %v not approved for team %v",
        [accel.type, input.variables.owner.value]
    )
}

# Deny if cost estimate exceeds team quota
deny[msg] {
    resource := input.resource_changes[_]
    resource.type == "google_container_node_pool"
    count_gpus := resource.change.after.node_count * resource.change.after.node_config[_].guest_accelerator[_].count
    count_gpus > data.team_gpu_quota[input.variables.owner.value]
    msg := sprintf(
        "Requested %v GPUs exceeds team quota of %v",
        [count_gpus, data.team_gpu_quota[input.variables.owner.value]]
    )
}

# Deny environments without required tags
deny[msg] {
    resource := input.resource_changes[_]
    resource.type in {"google_container_cluster", "aws_eks_cluster"}
    required_tags := {"cost-center", "team", "env-type", "ttl-date"}
    missing := required_tags - {k | resource.change.after.labels[k]}
    count(missing) > 0
    msg := sprintf("Environment missing required tags: %v", [missing])
}

# Deny H100 GPUs for sandbox environments
deny[msg] {
    input.variables.env_type.value == "sandbox"
    resource := input.resource_changes[_]
    resource.type == "google_container_node_pool"
    accel := resource.change.after.node_config[_].guest_accelerator[_]
    accel.type == "nvidia-h100-80gb"
    msg := "H100 GPUs are not permitted for sandbox environments; use a10g or cpu-only"
}

# platform/provisioner/llm_gateway.py
import httpx, json, subprocess

# Token budgets by environment type
BUDGETS = {
    "sandbox":   {"tokens_per_day": 500_000,    "rpm": 60},
    "staging":   {"tokens_per_day": 5_000_000,  "rpm": 300},
    "perf":      {"tokens_per_day": 20_000_000, "rpm": 1000},
    "prod-like": {"tokens_per_day": 50_000_000, "rpm": 2000},
}

def provision_gateway_credential(env_id: str, owner: str, models: list[str], env_type: str) -> dict:
    limits = BUDGETS[env_type]
    resp = httpx.post(
        "https://llm-gateway.internal/api/v1/credentials",
        json={"name": f"env-{env_id}", "owner": owner, "models": models,
              "limits": limits, "labels": {"env-id": env_id, "env-type": env_type}},
        headers={"Authorization": f"Bearer {GATEWAY_ADMIN_TOKEN}"},
        timeout=30,
    )
    resp.raise_for_status()
    return resp.json()  # {"api_key": "...", ...}

def inject_credential_to_k8s(api_key: str, models: list[str], namespace: str) -> None:
    secret = json.dumps({
        "apiVersion": "v1", "kind": "Secret",
        "metadata": {"name": "llm-gateway-creds", "namespace": namespace},
        "stringData": {
            "api_key": api_key,
            "gateway_url": "https://llm-gateway.internal",
            "models": ",".join(models),
        },
    })
    subprocess.run(["kubectl", "apply", "-f", "-"], input=secret.encode(), check=True)

# platform/expiry/controller.py  (runs as K8s CronJob nightly)
import datetime, httpx
from google.cloud import container_v1

def list_expiring_environments(project: str):
    client = container_v1.ClusterManagerClient()
    clusters = client.list_clusters(parent=f"projects/{project}/locations/-")
    today = datetime.date.today()
    for cluster in clusters.clusters:
        ttl_str = cluster.resource_labels.get("ttl-date")
        if ttl_str and datetime.date.fromisoformat(ttl_str) <= today:
            yield {"name": cluster.name, "team": cluster.resource_labels.get("team"), "ttl_date": ttl_str}

def trigger_teardown(env: dict) -> None:
    httpx.post(
        "https://api.github.com/repos/myorg/infra-gitops/dispatches",
        json={"event_type": "env-teardown", "client_payload": {"env_name": env["name"]}},
        headers={"Authorization": f"Bearer {GITHUB_TOKEN}", "Accept": "application/vnd.github+json"},
    ).raise_for_status()

def deregister_catalog(env_name: str) -> None:
    resp = httpx.delete(
        f"https://backstage.internal/api/catalog/entities/by-ref/resource:default/env-{env_name}",
        headers={"Authorization": f"Bearer {BACKSTAGE_TOKEN}"},
    )
    if resp.status_code not in (200, 404):
        resp.raise_for_status()

if __name__ == "__main__":
    for env in list_expiring_environments(project="myorg-platform"):
        print(f"Expiring: {env['name']} (TTL {env['ttl_date']})")
        trigger_teardown(env)
        deregister_catalog(env["name"])

# modules/genai-env/main.tf

variable "env_name"   { type = string }
variable "owner_team" { type = string }
variable "gpu_class"  { type = string; default = "none" }
variable "gpu_count"  { type = number; default = 0 }
variable "llm_models" { type = list(string) }
variable "ttl_days"   { type = number; default = 7 }
variable "project_id" { type = string }
variable "region"     { type = string; default = "us-central1" }

locals {
  ttl_date = formatdate("YYYY-MM-DD", timeadd(timestamp(), "${var.ttl_days * 24}h"))
  common_labels = {
    managed-by = "idp"
    team       = var.owner_team
    env-id     = var.env_name
    ttl-date   = local.ttl_date
  }
}

resource "google_container_cluster" "env" {
  name            = "genai-${var.env_name}"
  location        = var.region
  project         = var.project_id
  resource_labels = local.common_labels
  remove_default_node_pool = true
  initial_node_count       = 1
  workload_identity_config {
    workload_pool = "${var.project_id}.svc.id.goog"
  }
}

resource "google_container_node_pool" "gpu" {
  count      = var.gpu_class != "none" ? 1 : 0
  name       = "gpu-pool"
  cluster    = google_container_cluster.env.id
  node_count = var.gpu_count
  node_config {
    machine_type = var.gpu_class == "h100" ? "a3-highgpu-8g" : "a2-highgpu-1g"
    labels       = local.common_labels
    guest_accelerator {
      type  = var.gpu_class == "h100" ? "nvidia-h100-80gb" : "nvidia-tesla-a10g"
      count = var.gpu_class == "h100" ? 8 : 1
    }
  }
}

resource "google_storage_bucket" "artefacts" {
  name          = "genai-env-${var.env_name}-artefacts"
  location      = var.region
  project       = var.project_id
  force_destroy = true
  labels        = local.common_labels
  lifecycle_rule {
    action { type = "Delete" }
    condition { age = var.ttl_days + 2 }
  }
}

output "cluster_name"    { value = google_container_cluster.env.name }
output "artefact_bucket" { value = google_storage_bucket.artefacts.name }

# modules/genai-env/tests/sandbox.tftest.hcl
variables {
  env_name   = "ci-test-sandbox"
  owner_team = "platform-team"
  gpu_class  = "none"
  gpu_count  = 0
  llm_models = ["gpt-4o"]
  ttl_days   = 1
  project_id = "myorg-platform-test"
}

run "creates_cluster_with_labels" {
  command = plan

  assert {
    condition     = google_container_cluster.env.resource_labels["managed-by"] == "idp"
    error_message = "Cluster must carry managed-by=idp label"
  }
  assert {
    condition     = google_container_cluster.env.resource_labels["team"] == var.owner_team
    error_message = "Cluster must carry team label matching owner_team"
  }
}

run "no_gpu_pool_when_class_is_none" {
  command = plan

  assert {
    condition     = length(google_container_node_pool.gpu) == 0
    error_message = "gpu_class=none must not create a GPU node pool"
  }
}

run "artefact_bucket_has_lifecycle" {
  command = plan

  assert {
    condition     = length(google_storage_bucket.artefacts.lifecycle_rule) > 0
    error_message = "Artefact bucket must have a lifecycle rule for auto-deletion"
  }
}
